INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$AI-powered Ask assistant$q$, $q$Employees can ask questions in plain language and get answers pulled directly from verified knowledge base content instead of manually searching documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Cross-tool Slite Agent$q$, $q$On the Pro tier, the agent can search connected apps like Slack, Google Drive, GitHub, Jira, Linear, HubSpot, and Salesforce to surface answers beyond the wiki.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Doc verification and fact-checking$q$, $q$Pages can be reviewed, marked verified, or flagged with suggested fixes so outdated information does not quietly stay live.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Collaborative rich-text editor$q$, $q$Supports formatting, embedded video and diagrams, and file uploads up to 200MB for building detailed internal documentation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Knowledge Management Panel$q$, $q$Gives admins visibility into the state of the knowledge base, including stale or unverified content that needs attention.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$MCP and API access$q$, $q$Allows teams to connect Slite to custom workflows and tools beyond the built-in integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Single sign-on and reader seats$q$, $q$OpenID SSO and reader-only seats support broader, more controlled distribution of company knowledge on higher tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Custom domain publishing$q$, $q$Docs can be published externally under a custom domain, useful for public help centers or customer-facing knowledge bases.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$AI assistant answers questions directly from verified content rather than returning a list of links to search through$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Doc verification workflow helps keep a growing knowledge base accurate over time instead of going stale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Clean, focused editor that is easy for non-technical team members to adopt quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Cross-tool search on the Pro plan connects the wiki to tools teams already use daily$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Basic plan does not include the full AI agent or cross-tool search, which are the platform's most distinctive features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Per-seat pricing can get expensive for larger organizations compared to flat-rate wiki tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Smaller team size and funding relative to competitors like Notion or Confluence may raise long-term platform risk questions for some buyers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Less suited to teams that want an all-in-one workspace with tasks, databases, and project management alongside docs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$What is Slite used for$q$, $q$Slite is used as a team knowledge base and internal wiki for storing and instantly retrieving company information such as onboarding guides, policies, meeting notes, and process documentation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$How much does Slite cost$q$, $q$Slite starts at 10 dollars per user per month for the Basic plan billed annually, with a Pro plan at 20 dollars per user per month, and custom Enterprise pricing for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Does Slite have an AI assistant$q$, $q$Yes, Slite includes an AI assistant called Ask that answers employee questions directly from verified knowledge base content, and a broader Slite Agent on the Pro plan that can also search connected tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Is Slite the same company as Slab$q$, $q$No, Slite and Slab are separate companies in the knowledge base and wiki software category with different founders, funding histories, and product approaches.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Where is Slite headquartered$q$, $q$Slite is headquartered in Paris, France, and was founded in 2016 by Christophe Pasquier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Does Slite integrate with other tools$q$, $q$Yes, on the Pro plan Slite's agent can search across connected tools including Slack, Google Drive, GitHub, Jira, Linear, HubSpot, Salesforce, Intercom, and others.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Is there a free trial of Slite$q$, $q$Slite offers paid plans starting at the Basic tier; prospective users should check Slite's official pricing page for current trial availability.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Who is Slite best suited for$q$, $q$Slite is best suited for small to mid-sized teams in engineering, HR, operations, and sales that want a focused, AI-searchable knowledge base rather than a broader all-in-one workspace tool.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Employee onboarding hub$q$, $q$New hires can search or ask questions to quickly find onboarding guides, company policies, and team-specific processes without pinging colleagues.$q$, $q$HR and People Ops teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Engineering documentation$q$, $q$Engineering teams document architecture decisions, runbooks, and processes in a searchable format that stays current through the verification workflow.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Cross-tool knowledge retrieval$q$, $q$Sales and support teams use the Slite Agent to pull answers from connected tools like Salesforce, HubSpot, and Intercom without leaving the knowledge base.$q$, $q$Sales and customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Basic$q$, $q$$10 per user per month$q$, $q$annual$q$, NULL, $q$["Unlimited docs","AI search and answers","Doc verification workflow","Knowledge Management Panel","MCP and API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Pro$q$, $q$$20 per user per month$q$, $q$annual$q$, NULL, $q$["Everything in Basic","Slite Agent with cross-tool search","Doc fact-checking with suggested fixes","Agent workflows","Monthly AI credits per seat","OpenID single sign-on","Custom domain for public docs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Everything in Pro","Reader-only seats","Advanced security and controls","Audit logs","Service level agreement","Dedicated account manager","SCIM provisioning"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$overview$q$, $q$What Is Slite$q$, 2, ARRAY[$q$Slite is a cloud-based knowledge management and team wiki tool designed to be the single source of truth for a growing company's internal information. Rather than treating documentation as a static archive, Slite frames itself as a self-maintaining knowledge base: content is written collaboratively, verified on a schedule, and made instantly answerable through an AI assistant, so teams spend less time hunting through old Slack threads or forgotten Google Docs.$q$, $q$The platform was built for cross-functional teams such as engineering, HR, operations, and sales, who use it for onboarding guides, internal policies, meeting notes, and process documentation. Because Slite emphasizes searchability and trust in the content, it is often positioned against tools like Notion and Confluence for teams that specifically want a lightweight, focused knowledge base rather than a general-purpose workspace.$q$, $q$Slite's collaborative editor supports standard rich text formatting alongside embedded video, diagrams, and large file uploads, and documents can be organized into channels or collections so that departments can maintain their own areas of the knowledge base while still being searchable company-wide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The centerpiece of Slite's product is Ask, an AI assistant that answers employee questions in natural language by pulling directly from verified content inside the knowledge base, reducing the time spent searching for information manually. On higher tiers, this expands into a broader Slite Agent that can also search connected third-party tools such as Slack, Jira, Linear, GitHub, Google Drive, Salesforce, HubSpot, and Intercom, surfacing answers that live outside the wiki itself.$q$, $q$Slite also includes a doc verification workflow that helps teams keep information current: pages can be flagged for review, marked as verified, or fact-checked with suggested fixes so that outdated policies do not silently mislead employees. A Knowledge Management Panel gives admins visibility into which docs exist, which are stale, and where gaps might be forming.$q$, $q$Beyond AI and verification, Slite supports MCP and API access for custom integrations, OpenID single sign-on for centralized authentication, custom domains for publishing docs externally, and reader-only seats so companies can share knowledge with people who do not need full editing rights.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e4de8a34-adf7-4d4e-8978-1426321c23f0', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Slite uses per-user, per-month pricing billed annually across three tiers. The Basic plan, at 10 dollars per user per month, covers unlimited docs, AI search and answers, the doc verification workflow, the Knowledge Management Panel, and MCP and API access, making it a reasonable entry point for smaller teams that mainly need a well-organized, searchable wiki.$q$, $q$The Pro plan, at 20 dollars per user per month, adds the full Slite Agent with cross-tool search, doc fact-checking with suggested fixes, agent workflows, a pool of monthly AI credits per seat, OpenID single sign-on, and a custom domain for publicly published docs. This is the tier most growing companies choose once they want the knowledge base to actively connect with the rest of their software stack.$q$, $q$Enterprise pricing is custom and adds reader-only seats, advanced security controls, audit logs, a service level agreement, a dedicated account manager, priority support, custom agent sources, and SCIM provisioning, plus migration and onboarding assistance for larger, more security-conscious organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$PDF compression$q$, $q$Reduces PDF file size while preserving readable quality, useful for emailing or uploading large documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$PDF to Office conversion$q$, $q$Converts PDFs to and from Word, Excel, and PowerPoint formats without losing formatting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Merge and split tools$q$, $q$Combines multiple PDFs into one file or splits a single PDF into separate documents or page ranges.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$In-browser PDF editor$q$, $q$Lets users add or edit text, images, shapes, and annotations directly inside a PDF without desktop software.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$E-signature collection$q$, $q$Enables users to sign documents electronically or request signatures from others.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Password protection and removal$q$, $q$Adds or removes password security on PDF files to control document access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$OCR text recognition$q$, $q$Converts scanned or image-based PDFs into searchable and editable text.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Cloud storage integrations$q$, $q$Connects with services like Google Drive and Dropbox for direct file import and export.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Handles nearly every common PDF task in one browser-based suite instead of juggling multiple tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free plan is genuinely usable for light, occasional document tasks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Simple, uncluttered interface that requires no training to use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pro for Teams and Business plans add centralized billing for organizations with many users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free plan's daily processing or download limits can be restrictive for frequent users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Some advanced document manipulation tasks are handled better by dedicated desktop software like Adobe Acrobat$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pricing across sources varies for Pro and Pro for Teams tiers, so buyers should confirm current rates on the official site$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Heavier PDF editing (complex layout changes) is more limited than in full desktop PDF editors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$What is Smallpdf used for$q$, $q$Smallpdf is used for common PDF tasks such as compressing, converting, merging, splitting, editing, password-protecting, and e-signing PDF documents online.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Is Smallpdf free to use$q$, $q$Yes, Smallpdf offers a Free plan with access to core tools, though it includes a daily processing or download limit; paid Pro plans remove that limit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$How much does Smallpdf Pro cost$q$, $q$Smallpdf Pro is priced around 10 dollars per month when billed annually or 15 dollars per month when billed monthly, based on the official pricing page.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Where is Smallpdf based$q$, $q$Smallpdf is headquartered in Zurich, Switzerland, and was founded in 2013.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Does Smallpdf offer team plans$q$, $q$Yes, Smallpdf offers a Pro for Teams plan with per-seat pricing and a custom-priced Business plan for organizations with 20 or more users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Is Smallpdf secure for sensitive documents$q$, $q$Smallpdf uses encryption for file handling and processing, though users handling highly sensitive or regulated documents should review its current security and compliance documentation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Can Smallpdf convert PDFs to Word$q$, $q$Yes, Smallpdf includes tools to convert PDFs to and from Word, Excel, and PowerPoint formats.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Does Smallpdf have a mobile app$q$, $q$Yes, Smallpdf offers mobile apps in addition to its browser-based and desktop tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Quick document compression and sharing$q$, $q$Professionals compress large PDF files before emailing or uploading them to portals with size restrictions.$q$, $q$Office professionals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Contract signing and processing$q$, $q$Small businesses use e-signature and password tools to send, sign, and secure contracts and agreements.$q$, $q$Small business owners and HR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Document format conversion$q$, $q$Students and administrative staff convert PDFs to editable Word or Excel files for revision and reporting.$q$, $q$Students and administrative staff$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Access to core PDF tools","Daily download or processing limit","Basic compression and conversion"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pro$q$, $q$$10 per month (annual) or $15 per month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited processing","Batch tools","Priority support","Full tool suite access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pro for Teams$q$, $q$From $8 per user per month$q$, $q$annual$q$, NULL, $q$["Everything in Pro","Centralized team billing","Shared team management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Business$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["20 or more users","Dedicated support","Tailored contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$overview$q$, $q$What Is Smallpdf$q$, 2, ARRAY[$q$Smallpdf is a browser-based PDF platform founded in Zurich, Switzerland in 2013 that started as a single free tool for compressing PDF files and expanded into a full suite of more than 20 document tools. The company's stated mission is to make PDF and document tasks simple, secure, and reliable, and it claims to have served over 1.7 billion people since launch.$q$, $q$The product covers the most common everyday PDF needs: compressing large files, converting PDFs to and from Word, Excel, and PowerPoint, merging or splitting documents, editing text and images directly in a PDF, adding or removing passwords, and collecting legally binding e-signatures.$q$, $q$Smallpdf is used by individuals, freelancers, and businesses that need quick document processing without installing dedicated desktop software like Adobe Acrobat, and it is accessible through a web browser as well as desktop and mobile apps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Smallpdf offers PDF compression, conversion between PDF and Office formats, merging and splitting of multiple files, and an in-browser PDF editor for adding text, images, shapes, and annotations directly onto a document.$q$, $q$The suite also includes e-signature collection for getting documents signed electronically, password protection and removal tools for securing or unlocking PDFs, and an OCR (optical character recognition) tool for making scanned documents searchable and editable.$q$, $q$For teams, Smallpdf offers shared workspace features, integrations with cloud storage services like Google Drive and Dropbox, and centralized billing and user management on its Pro for Teams and Business plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Smallpdf follows a freemium model. The Free plan gives access to the core PDF tools, including compression, conversion, and basic editing, but caps usage with a daily download or processing limit, making it suitable for occasional, light use.$q$, $q$The Pro plan is aimed at individual power users who need unlimited processing, priced at roughly 10 dollars per month when billed annually or 15 dollars per month when billed monthly, and it removes the daily limits present on the free tier while unlocking batch tools and priority support.$q$, $q$Pro for Teams brings per-seat pricing, starting from around 8 dollars per user per month on annual billing, for organizations that want centralized billing and shared team management, while the custom-priced Business plan is built for larger organizations with 20 or more users that need dedicated support and tailored contract terms.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Unlimited sending mailboxes$q$, $q$Every plan allows connecting an unlimited number of email accounts to run campaigns from, rather than charging per mailbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$AI-powered inbox warm-up$q$, $q$Automatically builds sender reputation for connected mailboxes to improve inbox placement and reduce spam flagging.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Unified master inbox$q$, $q$Consolidates replies from all connected mailboxes and campaigns into a single inbox for reps to manage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Multi-step campaign sequences$q$, $q$Supports automated, multi-touch email sequences with conditional logic and follow-ups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Built-in email verification$q$, $q$Verifies prospect email addresses before sending to reduce bounce rates and protect sender reputation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Client workspaces for agencies$q$, $q$Higher-tier plans support multiple isolated client workspaces, useful for agencies managing outbound for several clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$CRM and API access$q$, $q$Pro and higher plans include native CRM access along with API and webhook access for custom integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$SmartDialer add-on$q$, $q$An optional voice calling add-on that lets teams combine cold calling with email outreach from the same platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$All plans include unlimited sending mailboxes, which can be more cost-effective than per-mailbox pricing tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Strong deliverability focus with AI warm-up and dedicated SmartServers on higher tiers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Agency-friendly features like multiple client workspaces on the Unlimited Prime plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Annual billing offers a meaningful 17 percent discount across all tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Pricing is based on contact and send volume, which can make costs harder to predict at scale than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Several capabilities like CRM access are gated behind the Pro plan and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Add-ons such as SmartServers and SmartDelivery add extra cost on top of the base subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Relatively young company (founded 2021) compared to some longer-established sales engagement platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$What is Smartlead used for$q$, $q$Smartlead is used for cold email outreach and sales engagement, letting teams send campaigns from unlimited mailboxes while managing deliverability and replies in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$How much does Smartlead cost$q$, $q$Smartlead's plans start at 39 dollars per month for the Base plan and go up to 379 dollars per month for the Unlimited Prime plan, with a 17 percent discount for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Does Smartlead limit the number of mailboxes$q$, $q$No, all Smartlead plans include unlimited email accounts; pricing is instead based on contacts stored and emails sent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Is Smartlead good for agencies$q$, $q$Yes, higher-tier plans include multiple client workspaces and dedicated sending infrastructure that are commonly used by agencies managing outbound for several clients.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Where is Smartlead based$q$, $q$Smartlead is headquartered in Sydney, Australia, and was founded in 2021 by Vaibhav Namburi.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Does Smartlead include email warm-up$q$, $q$Yes, Smartlead includes AI-powered warm-up to build sender reputation, with an Ultra Premium Warmup option available on Unlimited plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Does Smartlead have a CRM$q$, $q$Smartlead includes CRM access starting on its Pro plan and above.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Can Smartlead verify email addresses$q$, $q$Yes, Smartlead includes built-in email verification credits to reduce bounce rates before sending campaigns.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$High-volume cold outbound$q$, $q$Sales teams running large cold email campaigns use Smartlead's unlimited mailboxes and warm-up tools to scale sending while protecting deliverability.$q$, $q$B2B sales and SDR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Agency client outreach management$q$, $q$Agencies use client workspaces and dedicated SmartServers to run separate, isolated cold email campaigns for multiple clients from one account.$q$, $q$Outbound and lead-generation agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Founder-led outbound sales$q$, $q$Early-stage founders use Smartlead's Base or Pro plans to run their own outbound campaigns without hiring a dedicated SDR team.$q$, $q$Startup founders and small sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Base$q$, $q$$39 per month$q$, $q$monthly (17 percent off annually)$q$, NULL, $q$["Unlimited mailboxes","2,000 contacts storage","6,000 email sends","2,000 verified prospect emails"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Pro$q$, $q$$94 per month$q$, $q$monthly (17 percent off annually)$q$, NULL, $q$["30,000 contacts storage","90,000 email sends","30,000 verified prospect emails","CRM access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Unlimited Smart$q$, $q$$174 per month$q$, $q$monthly (17 percent off annually)$q$, NULL, $q$["Unlimited contacts","150,000 email sends","50,000 verified prospect emails","Eligible for Ultra Premium Warmup"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$Unlimited Prime$q$, $q$$379 per month$q$, $q$monthly (17 percent off annually)$q$, NULL, $q$["Unlimited contacts","500,000 email sends","170,000 verified prospect emails","3 SmartServers with OAuth","3 or more client workspaces"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$overview$q$, $q$What Is Smartlead$q$, 2, ARRAY[$q$Smartlead is a cold email and sales engagement platform built around the idea that deliverability, not just sending volume, determines the success of an outbound campaign. Founded in 2021 by Vaibhav Namburi and headquartered in Sydney, Australia, the platform lets users connect large numbers of sending mailboxes to a single account and run coordinated outreach campaigns across all of them.$q$, $q$The product is aimed at B2B sales teams, founders doing their own outbound, and agencies running cold email campaigns on behalf of multiple clients. Smartlead reports usage by more than 31,000 businesses, and its feature set reflects agency-style needs such as client workspaces and dedicated sending infrastructure on higher tiers.$q$, $q$Unlike many cold email tools that charge per mailbox, Smartlead includes unlimited email accounts on every plan and instead prices based on the volume of contacts stored and emails sent, which changes the cost calculus for teams running high-volume outbound.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Smartlead's core sending engine supports unlimited mailboxes per account, multi-step email sequences, and a unified master inbox where replies from all connected mailboxes and campaigns can be managed in one place.$q$, $q$AI-powered warm-up gradually builds sender reputation for new or underused inboxes to improve inbox placement, and on higher tiers this becomes Ultra Premium Warmup for more aggressive reputation management. The platform also includes built-in email verification to reduce bounce rates before sending.$q$, $q$For agencies and larger teams, Smartlead offers multiple client workspaces to separate campaigns and reporting by client, CRM access on the Pro tier and above, API and webhook access for custom integrations, and add-on products like SmartDialer for voice calling and SmartDelivery for deliverability monitoring.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7593c957-95bc-41e2-b981-f617ce468030', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Smartlead offers four core plans billed monthly, with a 17 percent discount available on annual billing. The Base plan, at 39 dollars per month, includes 2,000 contacts storage, 6,000 email sends, and 2,000 verified prospect emails, making it suited to individuals or small teams starting outbound.$q$, $q$The Pro plan, at 94 dollars per month, raises the limits to 30,000 contacts, 90,000 email sends, and 30,000 verified prospect emails, and adds CRM access. The Unlimited Smart plan, at 174 dollars per month and marked as most popular, removes the contact cap and allows 150,000 email sends with eligibility for Ultra Premium Warmup.$q$, $q$The top-tier Unlimited Prime plan, at 379 dollars per month, supports 500,000 email sends, includes three dedicated SmartServers with OAuth, and supports three or more client workspaces, making it the plan most suited to agencies running outbound at scale. Add-ons such as SmartSenders, SmartDelivery, SmartDialer, and dedicated SmartServers are priced separately.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Configurable applicant tracking system$q$, $q$Manages job requisitions, candidate pipelines, and hiring workflows with configuration options for different teams and regions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Sourcing marketplace$q$, $q$Integrates with a wide range of job boards, sourcing vendors, and assessment providers to help fill pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Candidate relationship management$q$, $q$Helps recruiters build and nurture talent pools ahead of open roles rather than starting from zero each time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Collaborative interview management$q$, $q$Coordinates interview scheduling and structured hiring team feedback within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Offer management$q$, $q$Supports creating, approving, and sending offers as part of the end-to-end hiring workflow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Hiring analytics and reporting$q$, $q$Provides visibility into funnel performance, time-to-hire, and diversity and inclusion metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Mobile hiring manager app$q$, $q$Lets hiring managers review candidates and provide feedback from a mobile device.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$API and HRIS integrations$q$, $q$Connects SmartRecruiters to broader HR systems, increasingly including SAP SuccessFactors following the 2025 acquisition.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Deep configurability suited to complex, high-volume, or global hiring workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Large marketplace of job board and vendor integrations reduces the need for separate sourcing tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Strong analytics and reporting for tracking hiring funnel performance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Now backed by SAP's resources following the 2025 acquisition, which may bring deeper enterprise integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Pricing beyond the Essential tier is not published and requires a custom quote, making budgeting harder upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Enterprise-oriented pricing and implementation costs make it a poor fit for very small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Ongoing integration with SAP following the 2025 acquisition creates some roadmap and pricing uncertainty for 2026$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Implementation and custom integration fees can add significantly to the first-year cost$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$What is SmartRecruiters used for$q$, $q$SmartRecruiters is used as an applicant tracking system and talent acquisition suite for sourcing, screening, interviewing, and hiring candidates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$How much does SmartRecruiters cost$q$, $q$The Essential plan is listed at 14,995 dollars per year; higher Professional, High Volume, and Complete tiers require a custom quote typically ranging from about 30,000 to over 120,000 dollars annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Is SmartRecruiters still an independent company$q$, $q$No, SAP completed its acquisition of SmartRecruiters in September 2025, and the platform now operates as part of SAP's human capital management portfolio.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Where is SmartRecruiters headquartered$q$, $q$SmartRecruiters was founded in 2010 and is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$How is SmartRecruiters priced$q$, $q$SmartRecruiters prices its plans based on a company's total employee headcount rather than the number of recruiter seats using the system.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Does SmartRecruiters integrate with SAP SuccessFactors$q$, $q$Following the September 2025 acquisition, deeper integration between SmartRecruiters and SAP SuccessFactors is expected to develop through 2026.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Is SmartRecruiters suited for small businesses$q$, $q$Not typically; its enterprise-oriented pricing and implementation costs make it better suited to mid-market and large organizations with complex hiring needs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Does SmartRecruiters offer a mobile app$q$, $q$Yes, SmartRecruiters provides a mobile app for hiring managers to review candidates and give feedback on the go.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$High-volume enterprise hiring$q$, $q$Large employers use SmartRecruiters to manage thousands of open requisitions and candidates across departments and regions with configurable workflows.$q$, $q$Enterprise talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Global recruiting operations$q$, $q$Multinational organizations use SmartRecruiters' marketplace of vendors and integrations to standardize hiring across different countries.$q$, $q$Global HR and recruiting operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Employer branding and candidate pipelines$q$, $q$Recruiting teams use candidate relationship management tools to build talent pools ahead of anticipated hiring needs.$q$, $q$Recruitment marketing and sourcing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Essential$q$, $q$$14,995 per year$q$, $q$annual$q$, NULL, $q$["Core applicant tracking system","Basic sourcing tools","Standard reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Professional$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Expanded sourcing marketplace access","Advanced workflow configuration","Candidate relationship management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$High Volume$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Built for high-volume hiring","Advanced automation","Enhanced reporting and analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$Complete$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Full platform capabilities","Priority support","Custom integrations available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$overview$q$, $q$What Is SmartRecruiters$q$, 2, ARRAY[$q$SmartRecruiters is a talent acquisition suite built around a modern applicant tracking system, designed to help mid-market and enterprise organizations manage the full hiring lifecycle from sourcing candidates through making an offer. Founded in 2010 and headquartered in San Francisco, the company built its reputation on a more open, marketplace-style platform that integrates with a wide range of job boards, assessment providers, and background check vendors.$q$, $q$In September 2025, SAP completed its acquisition of SmartRecruiters, bringing the platform into SAP's human capital management lineup alongside SuccessFactors. This is a significant change for prospective and existing customers, as licensing, pricing, and product roadmap decisions are expected to evolve as integration with SAP's broader enterprise software ecosystem continues through 2026.$q$, $q$SmartRecruiters is generally positioned for organizations with more complex, high-volume, or global hiring needs, rather than very small businesses, given its enterprise-oriented pricing model and depth of configuration options.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of SmartRecruiters is its applicant tracking system, which manages job requisitions, candidate pipelines, interview scheduling, collaborative hiring team feedback, and offer management in one place, with configurable workflows for different departments or regions.$q$, $q$Sourcing tools include a marketplace of integrated job boards and vendors, career site and job posting management, and candidate relationship management features for building and nurturing talent pipelines ahead of open positions.$q$, $q$The platform also provides reporting and analytics on hiring funnel performance, diversity and inclusion metrics, and time-to-hire, along with mobile apps for hiring managers and an API for connecting to HRIS and other enterprise systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7018fde8-f2e0-455a-ae95-59b95db2c107', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$SmartRecruiters prices its platform based on a company's total employee headcount rather than the number of recruiters using the system, which is a departure from many competing applicant tracking systems that charge per seat.$q$, $q$The Essential plan is the only tier with published list pricing, starting at 14,995 dollars per year, and is intended for smaller organizations with more limited hiring volume and feature needs.$q$, $q$The Professional, High Volume, and Complete tiers all require a custom quote from SmartRecruiters' sales team, with typical enterprise contracts reported to range from roughly 30,000 to over 120,000 dollars annually depending on headcount and feature requirements. Implementation fees of 5,000 to 25,000 dollars and separately priced custom integrations should be factored into total cost of ownership, and buyers should confirm current terms directly given the ongoing transition following the SAP acquisition.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Spreadsheet-style grid interface$q$, $q$Combines familiar spreadsheet rows and columns with row hierarchies and dependencies for project-style planning.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Automatic Gantt and calendar views$q$, $q$Generates Gantt charts and calendar views directly from sheet data without manual chart building.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Real-time dashboards and reports$q$, $q$Aggregates data from multiple sheets into visual dashboards for stakeholders and leadership.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Workflow automation$q$, $q$Triggers notifications, approvals, and status changes automatically based on conditions in the data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$WorkApps$q$, $q$Lets teams build lightweight custom applications on top of sheet data without traditional coding, available on Business and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Forms for data collection$q$, $q$Structured forms feed submitted data directly into sheets for tracking requests, intake, or approvals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Data Shuttle$q$, $q$Automates recurring data imports and exports between Smartsheet and other systems, available on Business and above.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Broad third-party integrations$q$, $q$Connects with tools like Microsoft 365, Google Workspace, Slack, and Salesforce for cross-platform workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Low learning curve for teams already comfortable with spreadsheets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Used at scale by a large share of Fortune 500 companies, indicating strong enterprise reliability$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Flexible enough to support project management, resource planning, and lightweight app-building on one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Strong automation and reporting capabilities reduce manual status updates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Business plan pricing at 32 dollars per user per month can get expensive for large teams compared to some competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Pro plan's user cap limits its usefulness for larger deployments without upgrading$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Spreadsheet-based interface can feel limiting for teams that need more visual, board-based project views without add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Now privately held after the 2025 Vista Equity Partners and Blackstone acquisition, which may affect long-term public roadmap transparency$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$What is Smartsheet used for$q$, $q$Smartsheet is used for project management, resource planning, marketing campaign tracking, and general work management using a spreadsheet-style interface.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$How much does Smartsheet cost$q$, $q$Smartsheet's Pro plan starts at 9 dollars per user per month billed annually, and the Business plan is 32 dollars per user per month, with custom Enterprise pricing available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Is Smartsheet still publicly traded$q$, $q$No, Smartsheet was publicly traded on the NYSE under the ticker SMAR until Vista Equity Partners and Blackstone completed a buyout in January 2025, making it privately held again.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Where is Smartsheet headquartered$q$, $q$Smartsheet is headquartered in Bellevue, Washington, and was founded in 2005.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Does Smartsheet have Gantt charts$q$, $q$Yes, Smartsheet automatically generates Gantt chart and calendar views from data entered into its spreadsheet-style sheets.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Can Smartsheet build custom apps$q$, $q$Yes, the WorkApps feature, available on the Business plan and above, lets teams build lightweight custom applications on top of sheet data.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Is Smartsheet used by large enterprises$q$, $q$Yes, Smartsheet reports that roughly 85 percent of Fortune 500 companies use its platform.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Does Smartsheet integrate with Microsoft and Google tools$q$, $q$Yes, Smartsheet integrates with Microsoft 365, Google Workspace, Slack, Salesforce, and other common business tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Enterprise project and portfolio tracking$q$, $q$Project management offices use Smartsheet to track multiple projects, dependencies, and resource allocation across departments.$q$, $q$Enterprise project management offices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Marketing campaign management$q$, $q$Marketing teams use sheets, forms, and dashboards to plan campaigns, collect creative requests, and report on status to leadership.$q$, $q$Marketing and creative operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$IT and operations workflow automation$q$, $q$IT teams build lightweight WorkApps and automated workflows on top of Smartsheet data to manage tickets, approvals, and asset tracking.$q$, $q$IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Pro$q$, $q$$9 per user per month$q$, $q$annual (billed monthly at $12/user/month)$q$, NULL, $q$["20 GB attachment storage","Core sheets and dashboards","Forms","Automation","Capped number of licensed users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Business$q$, $q$$32 per user per month$q$, $q$annual$q$, NULL, $q$["Unlimited licensed users","Unlimited attachment storage","WorkApps","Data Shuttle","Higher automation allowance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Advanced security and governance","Single sign-on","Deeper integrations","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$overview$q$, $q$What Is Smartsheet$q$, 2, ARRAY[$q$Smartsheet is a work management platform that combines a familiar spreadsheet-style grid with project management capabilities such as Gantt charts, dashboards, forms, and workflow automation. Founded in 2005 and headquartered in Bellevue, Washington, the company built its product to be approachable for business users who are comfortable with spreadsheets but need more structure and collaboration than a plain spreadsheet file can offer.$q$, $q$The company went public on the New York Stock Exchange under the ticker SMAR in April 2018 and grew into one of the more widely adopted enterprise work management platforms, with the company reporting usage by roughly 85 percent of Fortune 500 companies. In September 2024, Vista Equity Partners and Blackstone agreed to acquire Smartsheet for about 8.4 billion dollars, and that deal closed in January 2025, taking the company private again.$q$, $q$Smartsheet is used across a wide range of departments and industries for project tracking, resource and capacity planning, marketing campaign management, and IT operations, largely because its grid-based interface lowers the learning curve compared to more specialized project management tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Smartsheet's core building block is the sheet, a spreadsheet-like grid that can be enhanced with row hierarchies, dependencies, and automatically generated Gantt charts and calendar views, letting teams plan and track work without learning an entirely new interface.$q$, $q$Dashboards and reports let teams aggregate data across multiple sheets into real-time visual summaries for stakeholders, while Smartsheet's automation engine (workflows) can trigger notifications, approval requests, and status updates based on conditions set on the data.$q$, $q$On higher tiers, Smartsheet adds WorkApps for building lightweight custom applications on top of sheet data, Data Shuttle for automating data imports and exports, and forms for structured data collection that feeds directly into a sheet.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Smartsheet's Pro plan is priced at 9 dollars per user per month when billed annually (versus 12 dollars per month billed monthly), and includes 20 GB of attachment storage along with core sheets, dashboards, forms, and automation, though it is capped at a limited number of licensed users.$q$, $q$The Business plan, at 32 dollars per user per month, removes the user cap present on Pro and adds unlimited attachment storage, WorkApps for building custom lightweight apps, Data Shuttle for automated data movement, and a higher monthly automation allowance, making it the more common choice for larger or cross-departmental deployments.$q$, $q$An Enterprise plan with custom pricing is available for organizations that need advanced security controls, single sign-on, governance features, and deeper integrations, typically negotiated directly with Smartsheet's sales team based on organization size and requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Real-time live chat$q$, $q$Lets support agents chat with website visitors in real time and view visitor browsing activity for context.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Mira AI chatbot agent$q$, $q$An AI agent that automatically answers common customer questions and can hand off to a human agent when needed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Multichannel messaging$q$, $q$Integrates WhatsApp and Facebook Messenger so all conversations can be managed from one inbox.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Proactive chat triggers$q$, $q$Automatically engages visitors based on behavior, such as time on page or cart activity, to reduce abandonment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Automation workflows$q$, $q$Routes and tags conversations automatically based on rules to speed up response times.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Visitor tracking$q$, $q$Shows agents real-time visitor browsing data to give context before or during a conversation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Mobile apps$q$, $q$Lets support teams respond to live chat conversations from mobile devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Knowledge base integration for AI$q$, $q$Mira can be trained on a store's product catalog and content pages to answer product-specific questions automatically.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Genuinely usable free plan for very small sites or early-stage businesses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Combines live chat and AI chatbot in one affordable platform rather than requiring separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Multichannel support for WhatsApp and Messenger in addition to on-site chat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Annual billing offers a meaningful roughly 30 percent discount over monthly pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Free plan's 25 conversation per month cap is quite limiting for active stores$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Mira AI Agent is a separate add-on with its own pricing rather than being bundled into core plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Higher operator counts on Expert and Enterprise plans can add up in cost for larger support teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Smaller company size relative to larger live chat competitors like Intercom or Zendesk$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$What is Smartsupp used for$q$, $q$Smartsupp is used for live chat, AI chatbot support, and multichannel messaging to help websites and online stores engage visitors and increase sales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Is Smartsupp free$q$, $q$Yes, Smartsupp offers a Free plan for one operator with up to 25 conversations per month; paid plans remove that conversation limit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$How much does Smartsupp cost$q$, $q$Paid Smartsupp plans start around 17 dollars per month for the Solo plan, scaling up to around 83 dollars per month for the Expert plan, with custom Enterprise pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Where is Smartsupp based$q$, $q$Smartsupp is headquartered in Brno, Czech Republic, and was founded in 2013.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Does Smartsupp have an AI chatbot$q$, $q$Yes, Smartsupp offers an AI agent called Mira that can automatically answer customer questions and hand off complex conversations to human agents.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Does Smartsupp support WhatsApp and Messenger$q$, $q$Yes, Smartsupp integrates with WhatsApp and Facebook Messenger so all conversations can be managed alongside live chat in one inbox.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Is Smartsupp good for e-commerce$q$, $q$Yes, Smartsupp is commonly used by online stores for proactive engagement, visitor tracking, and reducing cart abandonment through live chat.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Does Smartsupp charge extra for AI features$q$, $q$Yes, the Mira AI Agent is sold as a separate add-on plan starting around 16 dollars per month, in addition to core live chat plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$E-commerce visitor engagement$q$, $q$Online stores use proactive chat triggers and visitor tracking to engage shoppers in real time and reduce cart abandonment.$q$, $q$E-commerce store owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$AI-assisted customer support$q$, $q$Support teams deploy the Mira AI Agent to automatically answer common product and order questions, freeing agents for complex cases.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Multichannel messaging support$q$, $q$Businesses consolidate WhatsApp, Messenger, and website chat conversations into a single inbox for consistent responses.$q$, $q$Small and mid-sized service businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["1 operator","25 conversations per month","14-day conversation history","Live chat, WhatsApp, and Messenger"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Solo$q$, $q$$17 per month$q$, $q$annual$q$, NULL, $q$["1 operator","Unlimited conversations","All channels plus 3 email addresses","50 AI replies per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Plus$q$, $q$$25 per month$q$, $q$annual$q$, NULL, $q$["3 operators","Unlimited conversations","All channels plus 10 email addresses","250 AI replies per month","Automation workflows"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$Expert$q$, $q$$83 per month$q$, $q$annual$q$, NULL, $q$["5 or more operators","Unlimited conversations","All channels plus 50 email addresses","500 AI replies per month","Premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$overview$q$, $q$What Is Smartsupp$q$, 2, ARRAY[$q$Smartsupp is a live chat and AI-assisted customer support platform founded in 2013 and headquartered in Brno, Czech Republic. The company built its product around the idea that real-time engagement with website visitors can directly increase online sales, not just resolve support questions after the fact.$q$, $q$The platform combines traditional live chat with an AI chatbot, branded Mira, and multichannel messaging support for WhatsApp and Facebook Messenger, letting small and mid-sized businesses manage conversations from multiple channels in a single unified inbox.$q$, $q$Smartsupp is particularly popular among European e-commerce businesses and service providers that want an affordable alternative to larger enterprise live chat platforms, while still offering AI automation for handling routine questions without adding headcount.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Smartsupp is real-time live chat, which lets support agents respond to website visitors instantly, view visitor activity and browsing behavior, and trigger proactive chat messages based on visitor behavior to reduce cart abandonment.$q$, $q$Smartsupp's Mira AI Agent can handle a set volume of conversations automatically, answering common questions from a knowledge base of up to tens of thousands of products and dozens of content pages, and can hand off complex conversations to a human agent seamlessly when needed.$q$, $q$The platform also supports multichannel messaging through WhatsApp and Facebook Messenger integrations, automation workflows for routing and tagging conversations, and mobile apps so support teams can respond to visitors from anywhere.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f54afb02-05b6-4fdd-aaff-7d81680e4f4d', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Smartsupp's Free plan supports one operator and up to 25 conversations per month with 14 days of conversation history, making it usable for very small sites but limited for active support volume.$q$, $q$Paid plans scale from Solo (about 17 dollars per month for one operator with unlimited conversations) through Plus (about 25 dollars per month for three operators and additional email channels) to Expert (about 83 dollars per month for five or more operators, premium support, and team features), all billed annually with roughly 30 percent savings versus monthly billing. An Enterprise tier starting around 280 dollars per month offers custom limits, a dedicated account manager, and API access.$q$, $q$Smartsupp's Mira AI Agent is sold as a separate add-on starting around 16 dollars per month for a limited number of AI-handled conversations per month, with the option to scale up conversation volume or move to a custom-priced unlimited AI agent plan for larger operations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Document automation$q$, $q$Generates legal documents from firm and practice area templates to reduce repetitive manual drafting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Automatic time capture$q$, $q$Tracks attorney time in the background as they work in Microsoft Word and Outlook, reducing missed billable time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Trust accounting and billing$q$, $q$Manages trust accounts, invoicing, and online payment collection natively within the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Matter and client management$q$, $q$Centralizes client and case information, communications, and documents in one place per matter.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Archie AI assistant$q$, $q$An AI-powered assistant that helps with drafting and client communication, available as an add-on on higher plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Client portal$q$, $q$Provides secure document sharing and communication between the firm and its clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Legal calendaring$q$, $q$Manages court dates, deadlines, and appointments integrated with matter records.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Firm insights and profitability reporting$q$, $q$Gives firm leadership visibility into staff activity, matter profitability, and overall performance, available on top tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Combines document management, billing, trust accounting, and case management in one integrated platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Automatic time capture in Word and Outlook can meaningfully reduce lost billable hours$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Built specifically for small law firm workflows across common practice areas$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Flexible add-ons like Archie AI and FamilyPro let firms customize the platform to their practice$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Public pricing page only shows a starting figure, requiring a sales call to get an exact quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Longer 36-month contract terms may not suit firms wanting more pricing flexibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Higher-tier features like advanced automation and AI assistance require moving up to more expensive plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Primarily built for US and Australian law firms, which may limit fit for firms in other jurisdictions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$What is Smokeball used for$q$, $q$Smokeball is used as legal practice management software for small and mid-sized law firms, combining document management, time tracking, billing, and case management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$How much does Smokeball cost$q$, $q$Smokeball's plans are listed as starting from 149 dollars per month, with exact pricing depending on firm size and whether a firm commits to a 12-month or 36-month contract.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Where is Smokeball based$q$, $q$Smokeball has a global head office in Sydney, Australia, and a US headquarters in Chicago, Illinois, and was founded in 2010.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Does Smokeball include trust accounting$q$, $q$Yes, trust accounting and reporting are included starting with the Bill plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Does Smokeball have an AI assistant$q$, $q$Yes, Smokeball offers an AI assistant called Archie for drafting and client communication as an add-on module.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$What practice areas does Smokeball support$q$, $q$Smokeball is used across practice areas including family law, personal injury, real estate, estate planning, litigation, and criminal law.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Does Smokeball automatically track billable time$q$, $q$Yes, Smokeball automatically captures time as attorneys work in Microsoft Word and Outlook, reducing manually logged hours.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Is Smokeball cloud-based$q$, $q$Yes, Smokeball is a cloud-based platform, and its Boost plan and above are fully browser-accessible.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Solo and small firm case management$q$, $q$Solo attorneys and small firms use Smokeball to manage matters, documents, billing, and trust accounting in one system.$q$, $q$Solo attorneys and small law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Document-heavy practice areas$q$, $q$Firms in real estate, estate planning, and family law use Smokeball's document automation to speed up repetitive drafting work.$q$, $q$Real estate, estate planning, and family law practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Firm growth and profitability tracking$q$, $q$Firm leadership uses Prosper+ reporting to track staff activity, matter profitability, and lead conversion as the firm scales.$q$, $q$Law firm partners and administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Bill$q$, $q$From $149 per month$q$, $q$12 or 36-month term$q$, NULL, $q$["Invoicing","Time and expense tracking","Online payments","Trust accounting and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Boost$q$, $q$From $149 per month$q$, $q$12 or 36-month term$q$, NULL, $q$["Everything in Bill","Client and matter management","Document management","Calendaring","Client portal"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Grow$q$, $q$From $149 per month$q$, $q$12 or 36-month term$q$, NULL, $q$["Everything in Boost","Practice area templates and calculators","Advanced document automation","Email management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Prosper+$q$, $q$From $149 per month$q$, $q$12 or 36-month term$q$, NULL, $q$["Everything in Grow","Firm insights reporting","Lead management","Advanced matter intake","Custom workflows and templates"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$overview$q$, $q$What Is Smokeball$q$, 2, ARRAY[$q$Smokeball is a cloud-based legal practice management platform founded in 2010 by a team of Australian legal technology veterans, Hunter Steele, Jane Oxley, and Bart Vadala. The company maintains a global head office in Sydney, Australia, and expanded into the United States in 2013 with a Chicago office that now serves as its US headquarters.$q$, $q$The platform is built specifically for small and mid-sized law firms and combines the core operational tools a firm needs day to day: document management and automation, time and expense tracking, trust accounting, billing, client and matter management, and calendaring, all inside one cloud-based system rather than several disconnected tools.$q$, $q$Smokeball has raised institutional funding, including a 30 million dollar Series B round in September 2021, and is used across a range of practice areas including family law, personal injury, real estate, estate planning, litigation, business sale and purchase, and criminal law.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Smokeball's document automation engine generates legal documents from firm-specific and practice area templates, reducing repetitive drafting work, and its Microsoft Word and Outlook integrations let attorneys work inside familiar tools while Smokeball automatically captures time and files documents to the right matter in the background.$q$, $q$Time and expense tracking, trust accounting, and billing are handled natively, with online payment collection and accounting integrations to reduce manual reconciliation, and a client portal allows secure document sharing and communication with clients.$q$, $q$Higher tiers add an AI assistant called Archie for drafting assistance and client communication, lead and intake management tools, firm-wide insights and profitability reporting, and advanced custom workflows and templates for firms with more complex process needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Smokeball organizes its pricing into four named plans of increasing capability: Bill, which covers invoicing, time and expense tracking, online payments, and trust accounting; Boost, which adds full client and matter management, document management, calendaring, and a client portal; Grow, which layers on practice area templates, advanced document automation, and email management; and Prosper+, the top tier, which adds firm insights reporting, lead management, and advanced matter intake.$q$, $q$On its official pricing page, Smokeball lists all four plans as starting from 149 dollars per month, with the exact price depending on firm size (1-2 users, 3-9 users, or 10 or more users) and whether the firm signs a 12-month or 36-month contract, longer terms generally reducing the effective monthly rate.$q$, $q$Because Smokeball does not publish granular per-tier, per-user pricing beyond the starting figure, firms need to request a personalized quote through the company's sales team to get an exact price, and can add optional modules like the Archie AI assistant, AutoTime, Intake, FamilyPro, and Workflows on top of their base plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Drag-and-drop design editor$q$, $q$An easy-to-use canvas for building social media graphics, ads, and blog headers without design experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$6,000-plus templates$q$, $q$Pre-sized templates for major social platforms and common marketing graphic formats.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$5 million-plus stock photos and graphics$q$, $q$A built-in royalty-free photo and graphics library accessible directly inside the editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$One-click background removal$q$, $q$Automatically removes image backgrounds without needing separate photo editing software.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Instant multi-format resizing$q$, $q$Resizes a single design across multiple social media dimensions without rebuilding it.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Custom font uploads$q$, $q$Lets paid users upload brand-specific fonts for on-brand design consistency.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Social scheduling integrations$q$, $q$Connects with tools like Buffer to publish designs directly to social media from within Snappa.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Team collaboration$q$, $q$The Team plan supports up to five users working within a shared account and design library.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Simple, focused interface that is easy to learn for non-designers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Generous free plan includes full access to templates and stock photos, just with a download cap$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$More affordable than many competitors for small teams needing basic social media graphics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$One-click background removal and multi-format resizing save significant manual editing time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Feature set is narrower than broader design platforms like Canva, with less support for presentations or complex layouts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Team plan caps out at five users, requiring a custom quote for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Free plan's 3 download per month limit is restrictive for anyone posting regularly$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Small company size (roughly 2-10 employees) may mean slower feature development compared to larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$What is Snappa used for$q$, $q$Snappa is used to create social media graphics, ads, blog headers, and other marketing images using templates, stock photos, and a drag-and-drop editor.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Is Snappa free$q$, $q$Yes, Snappa offers a free Starter plan with access to all templates and stock photos, limited to 3 downloads per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$How much does Snappa Pro cost$q$, $q$Snappa Pro costs 10 dollars per month when billed annually or 15 dollars per month when billed monthly, and removes the download limit for one user.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Where is Snappa based$q$, $q$Snappa is based in Ottawa, Canada, and was founded in 2015 by Marc Chouinard and Christopher Gimmer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$How is Snappa different from Canva$q$, $q$Snappa is generally positioned as a simpler, more affordable alternative focused specifically on social media and marketing graphics, while Canva covers a broader range of design and presentation use cases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Does Snappa support team collaboration$q$, $q$Yes, the Team plan supports up to five users collaborating within a shared account; larger teams need to contact Snappa for custom pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Does Snappa include stock photos$q$, $q$Yes, Snappa includes access to more than 5 million royalty-free HD stock photos and graphics directly in the editor.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Can Snappa remove image backgrounds$q$, $q$Yes, Snappa includes a one-click background removal tool on its paid plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Social media content creation$q$, $q$Social media managers use Snappa's templates and instant resizing to produce consistent posts across multiple platforms quickly.$q$, $q$Social media managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Small business marketing graphics$q$, $q$Small business owners create ads, promotional graphics, and blog headers without hiring a designer or learning complex software.$q$, $q$Small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Content marketing and blogging$q$, $q$Bloggers and content marketers use Snappa to design featured images and graphics that match their brand for articles and campaigns.$q$, $q$Content marketers and bloggers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Starter$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["1 user","6,000-plus templates","5 million-plus HD photos and graphics","3 downloads per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Pro$q$, $q$$10 per month (annual) or $15 per month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["1 user","Unlimited downloads","Buffer and social media integrations","Custom font uploads","Background removal"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$Team$q$, $q$$20 per month (annual) or $30 per month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["5 users","Unlimited downloads","Buffer and social media integrations","Custom font uploads","Background removal","Team collaboration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$overview$q$, $q$What Is Snappa$q$, 2, ARRAY[$q$Snappa is a web-based graphic design tool founded in 2015 in Ottawa, Canada by Marc Chouinard and Christopher Gimmer, built specifically to let people without design training create professional-looking marketing graphics quickly. The company runs as a small, largely bootstrapped team and has grown steadily, reporting 3.2 million dollars in revenue in 2024.$q$, $q$The platform is aimed squarely at small business owners, marketers, and social media managers who need graphics for platforms like Instagram, Facebook, Twitter, and YouTube, as well as blog headers and ads, without learning more complex tools like Photoshop or Illustrator.$q$, $q$Snappa is commonly compared to Canva, and is generally positioned as a simpler, more affordable, and more social-media-focused alternative rather than a broad design and presentation platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Snappa's core editor is a drag-and-drop design canvas with more than 6,000 templates pre-sized for social media posts, ads, blog graphics, and other common marketing formats, so users do not need to calculate dimensions manually.$q$, $q$The platform includes access to over 5 million royalty-free HD stock photos and graphics directly inside the editor, along with one-click background removal and the ability to instantly resize a single design into multiple social media dimensions without rebuilding it from scratch.$q$, $q$Paid plans add custom font uploads for on-brand designs, direct integrations with social scheduling tools like Buffer for publishing straight from the editor, and, on the Team plan, collaboration features that let multiple users share and work within the same account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c3b2ea2-f4c8-4a51-b3bc-e498903c1fb7', $q$pricing$q$, $q$Pricing Overview$q$, 2, ARRAY[$q$Snappa's Starter plan is free for one user and includes access to all 6,000-plus templates and the full stock photo and graphics library, but limits users to 3 downloads per month, making it suitable mainly for trying out the platform or very light use.$q$, $q$The Pro plan costs 10 dollars per month when billed annually or 15 dollars per month when billed monthly, and removes the download cap for a single user while adding unlimited downloads, custom font uploads, background removal, and social media scheduling integrations.$q$, $q$The Team plan costs 20 dollars per month billed annually or 30 dollars per month billed monthly, and extends the same unlimited-download feature set to five users with team collaboration tools; businesses needing more than five seats must contact Snappa directly for custom pricing.$q$]::text[], 2);
