-- ── Slite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Slite is an AI-powered team knowledge base and wiki platform that helps companies write, organize, verify, and instantly retrieve internal documentation.$q$, short_description),
  pricing_model = COALESCE($q$subscription (per-user, tiered)$q$, pricing_model),
  starting_price = COALESCE($q$$10 per user per month (Basic plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Slite Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Slite offers in 2026: AI knowledge base features, Basic, Pro, and Enterprise pricing, pros and cons, and whether it fits your team's docs workflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Slite is a team knowledge base and internal wiki platform founded in 2016 by Christophe Pasquier and headquartered in Paris, France. The company, which went through Y Combinator, has raised roughly 15.5 million dollars from investors including Index Ventures and Spark Capital, and employs an estimated 30 to 40 people. Slite positions itself as a self-maintaining, AI-powered knowledge base: teams write docs in a collaborative editor that supports rich formatting, embedded video, diagrams, and files up to 200MB, while an AI assistant called Ask answers employee questions directly from verified knowledge base content instead of making them search manually. A newer Slite Agent tier can also search across connected tools such as Slack, Google Drive, GitHub, Jira, Linear, HubSpot, Salesforce, and Intercom to surface answers from outside the wiki itself. Slite includes a doc verification and fact-checking workflow so admins can flag outdated pages and keep company information trustworthy over time. Pricing is tiered per user per month, starting with a Basic plan for straightforward documentation and search, moving up to a Pro plan that unlocks the AI agent, cross-tool search, and single sign-on, and topping out with a custom Enterprise plan for larger organizations that need audit logs, SCIM provisioning, and dedicated support. Typical customers are small to mid-sized teams in engineering, HR, operations, and sales who need a fast, searchable home for onboarding guides, policies, meeting notes, and workflows, and Slite counts companies like Airbnb and WeTransfer among its client base.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e4de8a34-adf7-4d4e-8978-1426321c23f0';

