-- ── Smallpdf ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Smallpdf is a Switzerland-based online PDF suite offering compression, conversion, editing, e-signature, and password tools used by over a billion people.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Pro from $10 per month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Zurich, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Smallpdf Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Smallpdf's PDF tools, Pro and Pro for Teams pricing, key features, pros and cons, and FAQs to decide if it fits your document workflow in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Smallpdf is an online PDF toolset founded in 2013 in Zurich, Switzerland, that grew from a single PDF compression tool into a suite of more than 20 tools covering compression, conversion, merging and splitting, editing, e-signature, and password protection or removal. The company is privately held, headquartered in Zurich with an additional team in Belgrade, and employs roughly 50 to 150 people depending on the source consulted. Smallpdf markets itself as having served over 1.7 billion people since launch, positioning it as one of the most widely used browser-based PDF utilities globally, competing with tools like Adobe Acrobat, iLovePDF, and PDFescape. The product runs entirely in the browser or through desktop and mobile apps, letting users upload a document, apply a tool such as compress, convert to Word, or add an e-signature, and download the result without installing dedicated desktop software. Smallpdf uses a freemium pricing model: the Free plan gives access to the core tools with a daily processing or download limit, while paid Pro plans remove those limits and add features like batch processing, more storage, and priority support. A Pro for Teams plan adds shared team management for organizations, and a custom-priced Business plan supports 20 or more users with dedicated support and tailored features. Because it handles sensitive documents, Smallpdf emphasizes encryption and secure file handling, and it integrates with cloud storage providers such as Google Drive and Dropbox for direct file import and export.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba837227-8967-47be-bd65-e9a86eafe9e3';

