-- ── SmartRecruiters ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SmartRecruiters is a talent acquisition suite for sourcing, screening, and hiring at scale, now operating as part of SAP following its 2025 acquisition.$q$, short_description),
  pricing_model = COALESCE($q$custom quote (enterprise, priced by employee headcount)$q$, pricing_model),
  starting_price = COALESCE($q$$14,995 per year (Essential plan)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SmartRecruiters Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how SmartRecruiters' talent acquisition suite works in 2026, including Essential and Enterprise pricing, key features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SmartRecruiters is a talent acquisition and recruiting software platform founded in 2010 and headquartered in San Francisco, California. Before being acquired, the company employed roughly 700 to 750 people and had raised significant venture funding to build out its applicant tracking system and broader hiring suite, which includes sourcing, candidate relationship management, interview scheduling, offer management, and reporting tools used by large and mid-sized employers. In September 2025, SAP completed its acquisition of SmartRecruiters, folding the platform into SAP's human capital management portfolio; industry sources expect a revised licensing and pricing structure to roll out in 2026 as the product is integrated with SAP SuccessFactors and related offerings. SmartRecruiters prices its platform based on a company's total employee headcount rather than the number of recruiter seats, with the Essential tier publicly listed at 14,995 dollars per year and higher Professional, High Volume, and Complete tiers requiring a custom quote that can range from roughly 30,000 to well over 120,000 dollars annually depending on organization size and feature needs. Implementation typically adds 5,000 to 25,000 dollars, and custom integrations are priced separately. The platform is aimed at mid-market and enterprise talent acquisition teams that need a modern, configurable applicant tracking system with strong sourcing and candidate experience tools, and it has historically been used by well-known global employers managing high volumes of hiring across multiple countries and business units.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7018fde8-f2e0-455a-ae95-59b95db2c107';

