-- ── Smartsheet ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Smartsheet is a spreadsheet-style work management and project collaboration platform used by the majority of Fortune 500 companies, now privately held after a 2025 buyout.$q$, short_description),
  pricing_model = COALESCE($q$subscription (per-user, tiered, plus enterprise)$q$, pricing_model),
  starting_price = COALESCE($q$$9 per user per month (Pro plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$1001-5000 employees$q$, company_size),
  headquarters = COALESCE($q$Bellevue, Washington$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Smartsheet Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Smartsheet's work management platform works in 2026, including Pro and Business pricing, key features, pros, cons, and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Smartsheet is a work management platform founded in 2005 by W. Eric Browne, Maria Colacurcio, John D. Creason, and Brent R. Frei, and headquartered in Bellevue, Washington. The company built its product around a familiar spreadsheet-style grid interface layered with project management features such as Gantt charts, dashboards, automated workflows, and forms, which let it reach a very wide range of non-technical business users in addition to project managers. Smartsheet went public on the New York Stock Exchange under the ticker SMAR in April 2018, and it grew to be used by roughly 85 percent of Fortune 500 companies according to the company's own marketing. In September 2024, Vista Equity Partners and Blackstone announced an agreement to acquire Smartsheet for approximately 8.4 billion dollars in cash at 56.50 dollars per share, and that acquisition closed in January 2025, meaning Smartsheet is now a privately held company rather than a publicly traded one, even though its NYSE: SMAR ticker remains part of its recent history. The platform offers tiered per-user pricing: a Pro plan at 9 dollars per user per month (billed annually) aimed at smaller teams with a cap on licensed users, and a Business plan at 32 dollars per user per month that removes the user cap and adds features like WorkApps, Data Shuttle, and expanded automation. An Enterprise tier with custom pricing adds advanced security, governance, and integration capabilities for large organizations. Smartsheet is commonly used for project tracking, resource management, marketing campaign planning, and IT operations across large, complex organizations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2713c5df-5f0a-4c25-8922-9c315b9b040b';

