-- ── Smartsupp ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Smartsupp is a Czech live chat, chatbot, and AI customer support platform that helps online stores and websites engage visitors and increase sales.$q$, short_description),
  pricing_model = COALESCE($q$freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans from $17 per month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Brno, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Smartsupp Review 2026: Live Chat Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Smartsupp's live chat and AI chatbot platform in 2026, including Free, Solo, Plus, and Expert pricing, key features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Smartsupp is a live chat, chatbot, and AI customer support platform founded in 2013 and headquartered in Brno, Czech Republic, with an estimated 11 to 50 employees. The company built its product to help e-commerce stores and general business websites engage visitors in real time, combining live chat, an AI chatbot agent branded Mira, and integrations with WhatsApp and Facebook Messenger so support teams can manage conversations across channels from one inbox. Smartsupp positions itself as a tool for increasing online sales, not just handling support tickets, with features like visitor tracking and proactive chat triggers designed to engage shoppers before they abandon a purchase. Pricing follows a freemium structure: the Free plan supports one operator and 25 conversations per month with 14-day conversation history, while paid tiers unlocking unlimited conversations start with the Solo plan at roughly 17 dollars per month for one operator, moving up through Plus and Expert plans that add more operators, more email channels, automation workflows, and premium support, with an Enterprise tier offering custom limits and a dedicated account manager. Smartsupp separately sells its Mira AI Agent as an add-on starting around 16 dollars per month for a set number of AI-handled conversations, which can be scaled up or replaced with an unlimited AI agent plan on custom pricing. The platform is aimed primarily at small and mid-sized online retailers and service businesses, particularly in Europe, that want an affordable way to combine human live chat with AI-assisted automation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f54afb02-05b6-4fdd-aaff-7d81680e4f4d';

