-- ── Smokeball ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Smokeball is a cloud-based legal practice management platform that combines document automation, time tracking, billing, and case management for small and mid-sized law firms.$q$, short_description),
  pricing_model = COALESCE($q$subscription (quote-based, tiered by contract term)$q$, pricing_model),
  starting_price = COALESCE($q$From $149 per month (varies by firm size and 12 or 36-month term)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chicago, Illinois (global headquarters in Sydney, Australia)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Smokeball Review 2026: Legal Software Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Smokeball's legal practice management software works in 2026, including Bill, Boost, Grow, and Prosper+ plans, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Smokeball is a cloud-based legal practice management platform founded in 2010 by Hunter Steele, Jane Oxley, and Bart Vadala, with a global head office in Sydney, Australia and a US headquarters in Chicago, Illinois established after the company expanded into the United States in 2013. Smokeball raised a 30 million dollar Series B funding round in September 2021 and has grown into one of the more widely used practice management platforms for small US law firms across practice areas including family law, personal injury, real estate, estate planning, litigation, and criminal law. The platform combines document management and automation, time and expense tracking, trust accounting, billing and online payments, client and matter management, calendaring, and an AI assistant called Archie that helps with drafting and client communication. Smokeball's pricing is organized into four named tiers, Bill, Boost, Grow, and Prosper+, each of increasing feature depth, all listed on the company's pricing page as starting from 149 dollars per month, with actual per-firm pricing varying based on the number of users (1-2, 3-9, or 10-plus) and whether the firm commits to a 12-month or 36-month contract term; firms must request a personalized quote to see exact figures. Add-ons available on top of the core plans include the Archie AI assistant, AutoTime for automatic time capture, Intake for lead and client intake management, FamilyPro for family law-specific tools, and Workflows for advanced process automation. Smokeball is positioned specifically for small to mid-sized law firms in the United States and Australia that want an integrated, cloud-based alternative to juggling separate billing, document, and case management tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '41637f09-c19d-4491-9683-03950483e648';

